import yaml, sys

REQUIRED_FIELDS = ["team", "service", "contact", "models_used",
                   "expected_traffic", "data_sensitivity", "compliance_class"]

VALID_COMPLIANCE = {"gdpr", "hipaa", "pci-dss", "internal-only"}

def validate_intake(path: str) -> list[str]:
    with open(path) as f:
        intake = yaml.safe_load(f)

    errors = []
    for field in REQUIRED_FIELDS:
        if field not in intake:
            errors.append(f"Missing required field: {field}")

    cc = intake.get("compliance_class", "")
    if cc not in VALID_COMPLIANCE:
        errors.append(f"compliance_class must be one of {VALID_COMPLIANCE}, got: {cc!r}")

    rps = intake.get("expected_traffic", {}).get("rps_p99", 0)
    if rps > 5000:
        errors.append(
            f"rps_p99={rps} exceeds default quota (5000). "
            "Request capacity increase with platform team before onboarding."
        )

    # HIPAA implies PHI — ensure loki audit tenant is listed
    if cc == "hipaa" and "audit" not in intake.get("loki_tenants_needed", []):
        errors.append("compliance_class=hipaa requires loki_tenants_needed to include 'audit'")

    return errors

if __name__ == "__main__":
    errs = validate_intake(sys.argv[1])
    if errs:
        for e in errs:
            print(f"ERROR: {e}")
        sys.exit(1)
    print("Intake validation passed.")

# terraform/modules/genai-tenant/main.tf
variable "team" { type = string }
variable "compliance_class" { type = string }
variable "loki_tenants" { type = list(string) }

# Grafana folder for this team's dashboards
resource "grafana_folder" "team" {
  title = "GenAI / ${var.team}"
  uid   = "genai-${var.team}"
}

# Grafana team and role assignment
resource "grafana_team" "team" {
  name = var.team
}

resource "grafana_team_preferences" "team" {
  team_id          = grafana_team.team.id
  home_dashboard_uid = "${var.team}-overview"
}

# Loki tenant labels — enforced at collector level
resource "kubernetes_config_map" "collector_tenant_filter" {
  metadata {
    name      = "collector-tenant-${var.team}"
    namespace = "observability"
  }
  data = {
    # Pipeline stage that routes this team's spans to their Loki tenant
    "pipeline.yaml" = yamlencode({
      pipeline_stages = [
        { match = {
            selector = "{team=\"${var.team}\"}"
            stages   = [{ tenant = { value = var.team } }]
        }}
      ]
    })
  }
}

# Alertmanager route for this team
resource "kubernetes_config_map_v1_data" "alertmanager_route" {
  # Appended to the platform Alertmanager config via config-reloader
  metadata { name = "alertmanager-routes"; namespace = "observability" }
  field_manager = "terraform"
  data = {
    "${var.team}.yaml" = yamlencode({
      receiver = "${var.team}-oncall"
      match    = { team = var.team }
    })
  }
}
